WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/50.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/50.0/apex.js")}

if({!ISNULL(Contact.ts2__Longitude__c) || ISNULL(Contact.ts2__Latitude__c)}) {
    alert('Contact has no geolocation fields populated');
} else {
    var cId = '{!Contact.Id}';
    var url = "/apex/ts2__JobMatch?cId=" + cId;
    win = window.open(url);
    win.focus();
}
